mapper.select:
	/*
		 SQL ID : selectOrgIdCheck
		 설  명 : 사용자 ID 중복 체크
 	*/
	SELECT CASE WHEN COUNT(TUI.USER_ID) = 0 THEN 'Y' ELSE 'N' END AS isUseable
	  FROM TB_LMS_USER_ACNT TUL
	     , TB_LMS_USR TUI
	 WHERE TUL.USER_ID = #{userId}
	 AND   TUL.USER_ID = TUI.USER_ID
	 AND   TUI.ORG_ID = #{orgId}

mapper.update:
	/*
		 SQL ID : update
		 설  명 : 사용자의 로그인 정보 수정
 	*/
	UPDATE TB_LMS_USER
	   SET ADMIN_LOGIN_ACPT_DIV_CD = #{adminLoginAcptDivCd}
	     , ACNT_LEAVE_DTTM = DECODE(#{userSts}, 'U','',ACNT_LEAVE_DTTM)
	     , ACNT_STSCD = #{userSts}
	     , MDFR_ID = #{mdfrId}
	     , MOD_DTTM = FN_DTTM()
	 WHERE USER_ID = #{userId}

mapper.delete:
	/*
		 SQL ID : delete
		 설  명 : 사용자의 로그인 정보 삭제
 	*/
	DELETE FROM TB_LMS_USER_ACNT
	 WHERE USER_ID = #{userId}

mapper.update:
/* SQL ID : updateFailInfo 설 명 : 사용자의 로그인 실패에 대한 정보 수정 */ UPDATE TB_LMS_USER SET LGN_CNTNU_FAIL_CNT = NVL(LGN_CNTNU_FAIL_CNT, 0) + 1
, LOGIN_FAIL_DTTM = FN_DTTM()
WHERE USER_ID = #{userId}

	/*
		 SQL ID : updatePassword
		 설  명 : 사용자의 비밀번호 변경
 	*/
	UPDATE TB_LMS_USER
	   SET USER_ENCPSWD = CASE WHEN #{userPass} = '' THEN USER_ENCPSWD WHEN #{userPass} = NULL THEN USER_ENCPSWD ELSE #{userPass} END
	     , MDFR_ID = #{mdfrId}
	     , MOD_DTTM = FN_DTTM()
	     , PSWD_CHG_REQ_DTTM = TO_CHAR(SYSDATE + FN_GET_CONFIG_VALUE('LOGIN','PSWDCHG'), 'YYYYMMDDHH24MISS')
	 WHERE USER_ID = #{userId}

	/*
		 SQL ID : updateTmpPassword
		 설  명 : 사용자의 비밀번호 변경
 	*/
	UPDATE TB_LMS_USER
	   SET TMP_PASS = #{tmpPass}
	     , MDFR_ID = #{mdfrId}
	     , MOD_DTTM = FN_DTTM()
	 WHERE USER_ID = #{userId}

	/*
		 SQL ID : updateStatus
		 설  명 : 사용자의 샹태 변경
 	*/
	UPDATE TB_LMS_USER
	   SET ACNT_STSCD = #{userSts}
	     , MDFR_ID = #{mdfrId}
	     , MOD_DTTM = FN_DTTM()
	 WHERE USER_ID = #{userId}

	/*
		 SQL ID : updateSns
		 설  명 : 사용자의 SNS_GBNCD입력
 	*/
	UPDATE TB_LMS_USER
	   SET SNS_GBNCD = #{snsDiv}
	     , SNS_KEY = #{snsKey}
	 WHERE USER_ID = #{userId}

mapper.insert:
	/*
		 SQL ID : insertSessionId
		 설  명 : 사용자 세션ID 저장
 	*/
	INSERT INTO TB_LMS_SESS (
		SESS_ID
		, USER_ID
		, RGTR_ID
		, REG_DTTM
	)
	VALUES (
		#{sessionId}
		, #{userId}
		, #{userId}
		, FN_DTTM()
	)

	/*
		 SQL ID : udpateSessionId
		 설  명 : 사용자 세션ID 수정
 	*/
	UPDATE TB_LMS_SESS SET
		  SESS_ID = #{sessionId}
		, REG_DTTM = FN_DTTM()
	WHERE USER_ID = #{userId}
